from datasets import Dataset

def format_gsm8k_for_grpo(problems):
    formatted = []
    for p in problems:
        formatted.append({
            "prompt": [{"role": "user", "content": p["prompt"]}],
            "answer": p["answer"],
        })
    return formatted

dataset_rlvr = Dataset.from_list(format_gsm8k_for_grpo(GSM8K_SAMPLE))

